     1→package openai
     2→
     3→import (
     4→	"bytes"
     5→	"context"
     6→	"encoding/json"
     7→	"fmt"
     8→	"io"
     9→	"iter"
    10→	"net/http"
    11→	"strings"
    12→
    13→	"google.golang.org/adk/model"
    14→	"google.golang.org/genai"
    15→)
    16→
    17→const defaultBaseURL = "https://api.openai.com/v1"
    18→
    19→// Config holds connection parameters for an OpenAI-compatible API.
    20→type Config struct {
    21→	APIKey  string
    22→	BaseURL string // defaults to https://api.openai.com/v1
    23→}
    24→
    25→// openaiModel implements model.LLM for OpenAI-compatible chat completion APIs.
    26→type openaiModel struct {
    27→	name    string
    28→	apiKey  string
    29→	baseURL string
    30→	client  *http.Client
    31→}
    32→
    33→// NewModel creates an OpenAI-backed model.LLM.
    34→func NewModel(_ context.Context, modelName string, cfg Config) (model.LLM, error) {
    35→	if cfg.APIKey == "" {
    36→		return nil, fmt.Errorf("openai: API key is required")
    37→	}
    38→	baseURL := cfg.BaseURL
    39→	if baseURL == "" {
    40→		baseURL = defaultBaseURL
    41→	}
    42→	return &openaiModel{
    43→		name:    modelName,
    44→		apiKey:  cfg.APIKey,
    45→		baseURL: baseURL,
    46→		client:  &http.Client{},
    47→	}, nil
    48→}
    49→
    50→func (m *openaiModel) Name() string { return m.name }
    51→
    52→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    53→// calls the API, and converts the response back to an LLMResponse.
    54→// Streaming is not implemented; the iterator always yields a single response.
    55→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    56→	return func(yield func(*model.LLMResponse, error) bool) {
    57→		resp, err := m.doRequest(ctx, req)
    58→		if err != nil {
    59→			yield(nil, err)
    60→			return
    61→		}
    62→		yield(resp, nil)
    63→	}
    64→}
    65→
    66→// Close is a no-op; the HTTP client has no persistent state.
    67→func (m *openaiModel) Close() {}
    68→
    69→// --- OpenAI API types ---
    70→
    71→type webSearchOptions struct{}
    72→
    73→type chatRequest struct {
    74→	Model            string            `json:"model"`
    75→	Messages         []chatMessage     `json:"messages"`
    76→	Tools            []chatTool        `json:"tools,omitempty"`
    77→	Temperature      *float32          `json:"temperature,omitempty"`
    78→	TopP             *float32          `json:"top_p,omitempty"`
    79→	MaxTokens        int32             `json:"max_tokens,omitempty"`
    80→	Stop             []string          `json:"stop,omitempty"`
    81→	Stream           bool              `json:"stream"`
    82→	WebSearchOptions *webSearchOptions `json:"web_search_options,omitempty"`
    83→}
    84→
    85→type chatMessage struct {
    86→	Role       string     `json:"role"`
    87→	Content    string     `json:"content,omitempty"`
    88→	ToolCalls  []toolCall `json:"tool_calls,omitempty"`
    89→	ToolCallID string     `json:"tool_call_id,omitempty"`
    90→}
    91→
    92→type toolCall struct {
    93→	ID       string       `json:"id"`
    94→	Type     string       `json:"type"`
    95→	Function functionCall `json:"function"`
    96→}
    97→
    98→type functionCall struct {
    99→	Name      string `json:"name"`
   100→	Arguments string `json:"arguments"`
   101→}
   102→
   103→type chatTool struct {
   104→	Type     string       `json:"type"`
   105→	Function chatFunction `json:"function"`
   106→}
   107→
   108→type chatFunction struct {
   109→	Name        string `json:"name"`
   110→	Description string `json:"description,omitempty"`
   111→	Parameters  any    `json:"parameters,omitempty"`
   112→}
   113→
   114→type chatResponse struct {
   115→	Choices []chatChoice `json:"choices"`
   116→	Usage   *chatUsage   `json:"usage,omitempty"`
   117→	Error   *apiError    `json:"error,omitempty"`
   118→}
   119→
   120→type chatChoice struct {
   121→	Message      chatMessage `json:"message"`
   122→	FinishReason string      `json:"finish_reason"`
   123→}
   124→
   125→type chatUsage struct {
   126→	PromptTokens     int32 `json:"prompt_tokens"`
   127→	CompletionTokens int32 `json:"completion_tokens"`
   128→	TotalTokens      int32 `json:"total_tokens"`
   129→}
   130→
   131→type apiError struct {
   132→	Message string `json:"message"`
   133→	Type    string `json:"type"`
   134→	Code    string `json:"code"`
   135→}
   136→
   137→// --- request/response conversion ---
   138→
   139→func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   140→	msgs := convertContents(req)
   141→	tools := convertTools(req)
   142→
   143→	chatReq := chatRequest{
   144→		Model:    m.name,
   145→		Messages: msgs,
   146→		Tools:    tools,
   147→		Stream:   false,
   148→	}
   149→
   150→	if req.Config != nil {
   151→		chatReq.Temperature = req.Config.Temperature
   152→		chatReq.TopP = req.Config.TopP
   153→		if req.Config.MaxOutputTokens > 0 {
   154→			chatReq.MaxTokens = req.Config.MaxOutputTokens
   155→		}
   156→		if len(req.Config.StopSequences) > 0 {
   157→			chatReq.Stop = req.Config.StopSequences
   158→		}
   159→	}
   160→
   161→	if hasWebSearch(req) {
   162→		chatReq.WebSearchOptions = &webSearchOptions{}
   163→	}
   164→
   165→	body, err := json.Marshal(chatReq)
   166→	if err != nil {
   167→		return nil, fmt.Errorf("openai: marshal request: %w", err)
   168→	}
   169→
   170→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/chat/completions", bytes.NewReader(body))
   171→	if err != nil {
   172→		return nil, fmt.Errorf("openai: create http request: %w", err)
   173→	}
   174→	httpReq.Header.Set("Content-Type", "application/json")
   175→	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   176→
   177→	httpResp, err := m.client.Do(httpReq)
   178→	if err != nil {
   179→		return nil, fmt.Errorf("openai: http request: %w", err)
   180→	}
   181→	defer httpResp.Body.Close()
   182→
   183→	respBody, err := io.ReadAll(httpResp.Body)
   184→	if err != nil {
   185→		return nil, fmt.Errorf("openai: read response: %w", err)
   186→	}
   187→
   188→	if httpResp.StatusCode != http.StatusOK {
   189→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   190→	}
   191→
   192→	var chatResp chatResponse
   193→	if err := json.Unmarshal(respBody, &chatResp); err != nil {
   194→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   195→	}
   196→
   197→	if chatResp.Error != nil {
   198→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   199→			chatResp.Error.Message, chatResp.Error.Type, chatResp.Error.Code)
   200→	}
   201→
   202→	return convertResponse(&chatResp), nil
   203→}
   204→
   205→// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   206→func convertContents(req *model.LLMRequest) []chatMessage {
   207→	var msgs []chatMessage
   208→
   209→	// System instruction.
   210→	if req.Config != nil && req.Config.SystemInstruction != nil {
   211→		var text string
   212→		for _, p := range req.Config.SystemInstruction.Parts {
   213→			if p.Text != "" {
   214→				text += p.Text
   215→			}
   216→		}
   217→		if text != "" {
   218→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   219→		}
   220→	}
   221→
   222→	// Conversation contents.
   223→	for _, c := range req.Contents {
   224→		role := mapRole(c.Role)
   225→
   226→		// Check each part: could be text, function_call, or function_response.
   227→		for _, p := range c.Parts {
   228→			switch {
   229→			case p.FunctionCall != nil:
   230→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   231→				msgs = append(msgs, chatMessage{
   232→					Role: "assistant",
   233→					ToolCalls: []toolCall{{
   234→						ID:   p.FunctionCall.ID,
   235→						Type: "function",
   236→						Function: functionCall{
   237→							Name:      p.FunctionCall.Name,
   238→							Arguments: string(argsJSON),
   239→						},
   240→					}},
   241→				})
   242→			case p.FunctionResponse != nil:
   243→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   244→				msgs = append(msgs, chatMessage{
   245→					Role:       "tool",
   246→					Content:    string(respJSON),
   247→					ToolCallID: p.FunctionResponse.ID,
   248→				})
   249→			case p.Text != "":
   250→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   251→			}
   252→		}
   253→	}
   254→
   255→	// Merge consecutive assistant messages with tool_calls.
   256→	msgs = mergeAssistantToolCalls(msgs)
   257→
   258→	return msgs
   259→}
   260→
   261→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   262→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   263→// one message rather than separate messages.
   264→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   265→	if len(msgs) == 0 {
   266→		return msgs
   267→	}
   268→	var merged []chatMessage
   269→	for _, msg := range msgs {
   270→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   271→			prev := &merged[len(merged)-1]
   272→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   273→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   274→				continue
   275→			}
   276→		}
   277→		merged = append(merged, msg)
   278→	}
   279→	return merged
   280→}
   281→
   282→// hasWebSearch checks whether the request contains a GoogleSearch tool marker,
   283→// indicating the caller wants web search capability.
   284→func hasWebSearch(req *model.LLMRequest) bool {
   285→	if req.Config == nil {
   286→		return false
   287→	}
   288→	for _, t := range req.Config.Tools {
   289→		if t != nil && t.GoogleSearch != nil {
   290→			return true
   291→		}
   292→	}
   293→	return false
   294→}
   295→
   296→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   297→func convertTools(req *model.LLMRequest) []chatTool {
   298→	if req.Config == nil || len(req.Config.Tools) == 0 {
   299→		return nil
   300→	}
   301→
   302→	var tools []chatTool
   303→	for _, t := range req.Config.Tools {
   304→		if t.GoogleSearch != nil {
   305→			continue
   306→		}
   307→		for _, fd := range t.FunctionDeclarations {
   308→			ct := chatTool{
   309→				Type: "function",
   310→				Function: chatFunction{
   311→					Name:        fd.Name,
   312→					Description: fd.Description,
   313→				},
   314→			}
   315→			if fd.Parameters != nil {
   316→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   317→			}
   318→			tools = append(tools, ct)
   319→		}
   320→	}
   321→	return tools
   322→}
   323→
   324→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   325→// the OpenAI function parameters format (JSON Schema).
   326→func schemaToMap(s *genai.Schema) map[string]any {
   327→	m := map[string]any{}
   328→	if s.Type != "" {
   329→		m["type"] = strings.ToLower(string(s.Type))
   330→	}
   331→	if s.Description != "" {
   332→		m["description"] = s.Description
   333→	}
   334→	if len(s.Enum) > 0 {
   335→		m["enum"] = s.Enum
   336→	}
   337→	if s.Items != nil {
   338→		m["items"] = schemaToMap(s.Items)
   339→	}
   340→	if len(s.Properties) > 0 {
   341→		props := map[string]any{}
   342→		for k, v := range s.Properties {
   343→			props[k] = schemaToMap(v)
   344→		}
   345→		m["properties"] = props
   346→	}
   347→	if len(s.Required) > 0 {
   348→		m["required"] = s.Required
   349→	}
   350→	return m
   351→}
   352→
   353→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   354→func convertResponse(resp *chatResponse) *model.LLMResponse {
   355→	llmResp := &model.LLMResponse{
   356→		TurnComplete: true,
   357→	}
   358→
   359→	if len(resp.Choices) == 0 {
   360→		llmResp.Content = genai.NewContentFromText("", "model")
   361→		return llmResp
   362→	}
   363→
   364→	choice := resp.Choices[0]
   365→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   366→
   367→	content := &genai.Content{Role: "model"}
   368→
   369→	// Text content.
   370→	if choice.Message.Content != "" {
   371→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   372→	}
   373→
   374→	// Tool calls.
   375→	for _, tc := range choice.Message.ToolCalls {
   376→		var args map[string]any
   377→		if tc.Function.Arguments != "" {
   378→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   379→		}
   380→		content.Parts = append(content.Parts, &genai.Part{
