   661→**Step 2: Rewrite doRequest for Responses API**
   662→
   663→```go
   664→func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   665→	items, instructions := convertInputs(req)
   666→	tools := convertResponseTools(req, m.wsConfig)
   667→
   668→	apiReq := responsesRequest{
   669→		Model:        m.name,
   670→		Input:        items,
   671→		Instructions: instructions,
   672→		Tools:        tools,
   673→		Store:        false,
   674→	}
   675→
   676→	if req.Config != nil {
   677→		apiReq.Temperature = req.Config.Temperature
   678→		apiReq.TopP = req.Config.TopP
   679→		if req.Config.MaxOutputTokens > 0 {
   680→			apiReq.MaxTokens = req.Config.MaxOutputTokens
   681→		}
   682→	}
   683→
   684→	body, err := json.Marshal(apiReq)
   685→	if err != nil {
   686→		return nil, fmt.Errorf("openai: marshal request: %w", err)
   687→	}
   688→
   689→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/responses", bytes.NewReader(body))
   690→	if err != nil {
   691→		return nil, fmt.Errorf("openai: create http request: %w", err)
   692→	}
   693→	httpReq.Header.Set("Content-Type", "application/json")
   694→	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   695→
   696→	httpResp, err := m.client.Do(httpReq)
   697→	if err != nil {
   698→		return nil, fmt.Errorf("openai: http request: %w", err)
   699→	}
   700→	defer httpResp.Body.Close()
   701→
   702→	respBody, err := io.ReadAll(httpResp.Body)
   703→	if err != nil {
   704→		return nil, fmt.Errorf("openai: read response: %w", err)
   705→	}
   706→
   707→	if httpResp.StatusCode != http.StatusOK {
   708→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   709→	}
   710→
   711→	var apiResp responsesResponse
   712→	if err := json.Unmarshal(respBody, &apiResp); err != nil {
   713→		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   714→	}
   715→
   716→	if apiResp.Error != nil {
   717→		return nil, fmt.Errorf("openai: API error: %s (type=%s, code=%s)",
   718→			apiResp.Error.Message, apiResp.Error.Type, apiResp.Error.Code)
   719→	}
   720→
   721→	return convertResponseOutput(&apiResp), nil
   722→}
   723→```
